// Stub for JIT-generated chlkc_descriptors.h (clang-tidy analysis only)
//
// The real chlkc_descriptors.h is generated by tt_metal/jit_build/genfiles.cpp
// and emits (under UCK_CHLKC_MATH):
//
//   #include "llk_defs.h"
//   constexpr ckernel::MathFidelity MATH_FIDELITY = static_cast<ckernel::MathFidelity>(N);
//   constexpr bool APPROX = <bool>;
//
// By the time chlkc_descriptors.h is included (from chlkc_list.h, after
// ckernel.h → llk_defs.h), ckernel::MathFidelity is already in scope, so
// the static_cast is valid.  We replicate that structure here.
//
// All pack/unpack data-format arrays and tile-dimension arrays are already
// provided by the force-included kernel_clang_tidy_prelude.h, so this stub
// only needs to handle the math scalars.

#pragma once

#ifdef UCK_CHLKC_MATH
// llk_defs.h defines ckernel::MathFidelity; it is already included transitively
// through ckernel.h, but include explicitly here to match the generated file.
#include "llk_defs.h"
// LoFi (= 0) is a safe default for static analysis; the actual value doesn't
// affect clang-tidy results.
constexpr ckernel::MathFidelity MATH_FIDELITY = static_cast<ckernel::MathFidelity>(0);
#endif
